	"ELECTRON_RUN_AS_NODE",
];

export function getLanguageConfig(language: string): LanguageConfig | null {
	return LANGUAGE_CONFIGS[language] ?? null;
}

export function sanitizeEnvironment(baseEnv: NodeJS.ProcessEnv, languageConfig: LanguageConfig): NodeJS.ProcessEnv {
	const clean: NodeJS.ProcessEnv = { ...baseEnv };
	const toStrip = new Set([...DANGEROUS_ENV_VARS, ...languageConfig.envStrip]);
	for (const key of toStrip) {
		delete clean[key];
	}
	return clean;
}

import type { ExtensionAPI, ExtensionContext, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import * as fs from "node:fs";
import * as path from "node:path";
import { fileURLToPath } from "node:url";
import { loadConfig } from "../config.ts";
import { MemoryDB } from "../store/sqlite.ts";
import { handleMemorySearch, type MemorySearchInput } from "../tools/memory-search.ts";
import { handleMemoryStore, type MemoryStoreInput } from "../tools/memory-store.ts";
import { handleMemoryRecall, type MemoryRecallInput } from "../tools/memory-recall.ts";
import { handleMemoryStatus, type MemoryStatusInput } from "../tools/memory-status.ts";
import { generatePIMemoryMd } from "../memory/hierarchical.ts";
import { autoSeedModels } from "../memory/mental-models.ts";
import { analyzeSession } from "../compound/analyzer.ts";
import { consolidateMemories } from "../memory/reflect.ts";
import { createSessionTracker } from "../continuity/tracker.ts";
import { buildResumeContext, formatResumeContext } from "../continuity/resumer.ts";

let currentCtx: ExtensionContext | undefined;
let memoryDB: MemoryDB | undefined;

function getDB(cwd: string): MemoryDB {
	if (memoryDB && memoryDB.cwd === cwd) return memoryDB;
	memoryDB?.close();
	memoryDB = new MemoryDB(cwd);
	memoryDB.open();
	return memoryDB;
}

export function registerPiMemory(pi: ExtensionAPI): void {
	// в”Җв”Җ session_start в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const config = loadConfig(ctx.cwd);
		if (!config.enabled) return;

		const db = getDB(ctx.cwd);

		// Auto-seed mental models
		if (config.mentalModels.enabled) {
			autoSeedModels(db.getConnection(), config.mentalModels.seeds);
		}

		// Generate PI_MEMORY.md if auto-generate is enabled
		if (config.autoGenerateSummary) {
			try {
				generatePIMemoryMd(db.getConnection(), ctx.cwd);
			} catch { /* non-critical */ }
		}

		// Session resume
		if (config.continuity.enabled && config.continuity.autoResume) {
			try {
				const resumeCtx = buildResumeContext(db.getConnection());
				if (resumeCtx) {
					formatResumeContext(resumeCtx, config.continuity.maxResumeContext);
				}
			} catch { /* non-critical */ }
		}
	});

	// в”Җв”Җ session_shutdown в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
	pi.on("session_shutdown", () => {
		if (!currentCtx) return;
		const config = loadConfig(currentCtx.cwd);
		const db = memoryDB;
		if (!db?.isOpen) {
			memoryDB?.close();
			memoryDB = undefined;
			currentCtx = undefined;
			return;
		}

		const conn = db.getConnection();

		// Knowledge compounding
		if (config.autoCompound && config.compounding.enabled) {
			try {
				const sessionId = (currentCtx as unknown as Record<string, unknown>).sessionId as string | undefined;
				if (sessionId) {
					analyzeSession(conn, currentCtx.cwd, sessionId, config.compounding.dedupThreshold);
				}
			} catch { /* non-critical */ }
		}

		// Consolidation
		try {
			consolidateMemories(conn, config.maxSolutionsAge);
		} catch { /* non-critical */ }

		// Update PI_MEMORY.md
		if (config.autoGenerateSummary) {
			try {
				generatePIMemoryMd(conn, currentCtx.cwd);
			} catch { /* non-critical */ }
		}

		db.close();
		memoryDB = undefined;
		currentCtx = undefined;
	});

	// в”Җв”Җ tool_call tracking в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
	pi.on("tool_call", (event) => {
		if (!currentCtx || !memoryDB?.isOpen) return;
		const config = loadConfig(currentCtx.cwd);
		if (!config.enabled) return;

		const toolName = (event as { toolName?: string }).toolName;
		if (toolName === "edit" || toolName === "write") {
			const input = (event as { input?: Record<string, unknown> }).input;
			const filePath = typeof input?.file === "string" ? input.file :
				typeof input?.path === "string" ? input.path : undefined;
			if (filePath) {
				const sessionId = (currentCtx as unknown as Record<string, unknown>).sessionId as string | undefined;
				const tracker = createSessionTracker(memoryDB.getConnection(), sessionId ?? "unknown");
				tracker.trackEdit(filePath, 0);
			}
		}
	});

	// в”Җв”Җ resources_discover в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
	try {
		pi.on("resources_discover", () => {
			const extDir = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..", "..", "skills");
			if (fs.existsSync(extDir)) return { skillPaths: [extDir] };
			return {};
		});
	} catch { /* older Pi without resources_discover */ }

	// в”Җв”Җ Register tools в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

	const toolResult = (text: string) =>
		({ content: [{ type: "text" as const, text }], details: {} });

	const memorySearchTool: ToolDefinition = {
		name: "memory_search",
		label: "Memory Search",
		description: "Search persistent memory for relevant knowledge, solutions, decisions, and patterns",
		parameters: Type.Object({
			query: Type.String({ description: "Natural language query" }),
			maxResults: Type.Optional(Type.Number({ description: "Maximum results to return (default: 5)" })),
			scope: Type.Optional(Type.String({ description: "Search scope filter: all, solutions, decisions, gotchas, conventions" })),
			detail: Type.Optional(Type.String({ description: "Detail level: compact, medium, full" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const db = getDB(cwd);
			const text = handleMemorySearch(db.getConnection(), params as unknown as MemorySearchInput);
			return toolResult(text);
		},
	};

	const memoryStoreTool: ToolDefinition = {
		name: "memory_store",
		label: "Memory Store",
		description: "Store knowledge in persistent memory (gotchas, conventions, decisions, patterns, architecture)",
		parameters: Type.Object({
			category: Type.String({ description: "Knowledge category: gotcha, convention, decision, pattern, architecture" }),
			title: Type.String({ description: "Title for the stored knowledge" }),
			content: Type.String({ description: "Content to store" }),
			metadata: Type.Optional(Type.Object({
				files: Type.Optional(Type.Array(Type.String())),
				tags: Type.Optional(Type.Array(Type.String())),
				severity: Type.Optional(Type.String()),
			})),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const db = getDB(cwd);
			const text = handleMemoryStore(db.getConnection(), cwd, params as unknown as MemoryStoreInput);
			return toolResult(text);
		},
	};

	const memoryRecallTool: ToolDefinition = {
		name: "memory_recall",
		label: "Memory Recall",
		description: "Recall relevant memories with progressive disclosure based on budget",
		parameters: Type.Object({
			context: Type.String({ description: "What context is needed" }),
			budget: Type.Optional(Type.Number({ description: "Max bytes to return (default: 2048)" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const db = getDB(cwd);
			const text = handleMemoryRecall(db.getConnection(), params as unknown as MemoryRecallInput);
			return toolResult(text);
		},
	};

	const memoryStatusTool: ToolDefinition = {
		name: "memory_status",
		label: "Memory Status",
		description: "Get memory status, stats, or manage the memory database",
		parameters: Type.Object({
			action: Type.String({ description: "Action to perform: status, stats, reindex, compact, export" }),
			format: Type.Optional(Type.String({ description: "Output format: text, json" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const db = getDB(cwd);
			const text = handleMemoryStatus(db.getConnection(), db.dbPath, params as unknown as MemoryStatusInput);
			return toolResult(text);
		},
	};

	for (const tool of [memorySearchTool, memoryStoreTool, memoryRecallTool, memoryStatusTool]) {
		try {
			pi.registerTool(tool);
		} catch { /* tool registration may not be available */ }
	}
}

import type { ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { registerPipelineTools } from "./tool-registry.ts";
import { emptyPipelineState } from "../types.ts";
import { detectAmbiguity } from "../clarify/ambiguity.ts";
import { totalAmbiguityScore } from "../clarify/scoring.ts";
import { detectComplexity } from "../adaptive/complexity.ts";
import { handlePlan, handlePlanDeepen, handlePlanGo, handlePlanStatus } from "../commands/plan.ts";
import { handlePlanReview } from "../commands/review.ts";
import { handleVerify, handleVerifyEvidence } from "../commands/verify.ts";
import { handleClarify } from "../commands/clarify.ts";
import { handleGo } from "../commands/go.ts";

export function registerPiPipeline(pi: ExtensionAPI): void {
	// Pipeline state is session-scoped
	let state = emptyPipelineState();

	pi.on("session_start", (_event, ctx: ExtensionContext) => {
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		// Reset pipeline state for new session
		state = emptyPipelineState();

		// Register pipeline tools
		registerPipelineTools(pi);

		// Register slash commands
		registerPipelineCommands(pi, ctx, () => state, (s) => { state = s; });
	});

	// Hook: input вҶ’ intent analysis
	pi.on("input", (event) => {
		const text = event.text;
		if (!text) return;

		const signals = detectAmbiguity(text);
		const score = totalAmbiguityScore(signals);

		if (score > 0.5 && state.mode === "IDLE") {
			// Could inject plan mode prefix for complex requests
			state = { ...state, ambiguityScore: score };
		}
	});

	// Hook: context вҶ’ pipeline context injection
	// ContextEventResult allows returning additional messages to inject into context.
	// We use `as never` to bypass the complex AgentMessage type from pi-agent-core.
	const contextHook = (): { messages?: Array<Record<string, unknown>> } | undefined => {
		if (state.mode === "GATHERING" || state.mode === "SPEC'ING" || state.mode === "PLANNING") {
			return {
				messages: [
					{ role: "user", content: "[system] You are in planning mode. Ask clarifying questions before implementing." },
				],
			};
		}

		if (state.mode === "EXECUTING") {
			return {
				messages: [
					{ role: "user", content: "[system] Follow the approved plan. Report evidence when each task completes." },
				],
			};
		}

		if (state.mode === "REVIEWING") {
			return {
				messages: [
					{ role: "user", content: "[system] Review ONLY what was asked. Do not add scope." },
				],
			};
		}

		return undefined;
	};
	// eslint-disable-next-line @typescript-eslint/no-explicit-any
	(pi as any).on("context", contextHook as any);
}

function registerPipelineCommands(
	pi: ExtensionAPI,
	ctx: ExtensionContext,
	getState: () => typeof import("../types.ts").emptyPipelineState extends () => infer R ? R : never,
	setState: (s: typeof import("../types.ts").emptyPipelineState extends () => infer R ? R : never) => void,
): void {
	const state = getState;
	const set = setState;

	// /plan command
	pi.registerCommand("plan", {
		description: "Plan mode: /plan <task>, /plan deepen, /plan go, /plan status, /plan review",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const arg = args?.trim().toLowerCase() ?? "";

			if (arg.startsWith("deepen")) {
				const result = handlePlanDeepen(state(), (t) => t); // identity analyzer as default
				set(result.state);
				cmdCtx.ui.notify(result.message);
			} else if (arg === "go") {
				const result = handlePlanGo(state());
				set(result.state);
				cmdCtx.ui.notify(result.message);
			} else if (arg === "status") {
				const result = handlePlanStatus(state());
				cmdCtx.ui.notify(result.message);
			} else if (arg === "review") {
				const { createSpecComplianceReview, createCodeQualityReview } = await import("../review/two-stage.ts");
				const stage1 = createSpecComplianceReview();
				const result = handlePlanReview(state(), stage1);
				set(result.state);
				cmdCtx.ui.notify(result.message);
			} else {
				// Use the original (non-lowered) args for the task description
				const taskArgs = args?.trim() ?? "";
				const result = handlePlan(taskArgs, state(), config);
				set(result.state);
				cmdCtx.ui.notify(result.message);
			}
		},
	});

	// /verify command
	pi.registerCommand("verify", {
		description: "Run verification gates: /verify, /verify evidence",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const arg = args?.trim().toLowerCase() ?? "";

			if (arg === "evidence") {
				const taskCtx = {
					changedFiles: [],
					assistantOutput: "",
					hasLsp: false,
					cwd: ctx.cwd,
				};
				const result = handleVerifyEvidence(state(), taskCtx);
				cmdCtx.ui.notify(result.message);
			} else {
				const taskCtx = {
					changedFiles: [],
					assistantOutput: "",
					hasLsp: false,
					cwd: ctx.cwd,
				};
				const result = handleVerify(state(), taskCtx, config);
				cmdCtx.ui.notify(result.message);
			}
		},
	});

	// /clarify command
	pi.registerCommand("clarify", {
		description: "Force clarification: /clarify <message>",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const message = args?.trim() ?? "";
			if (!message) {
				cmdCtx.ui.notify("Usage: /clarify <message to analyze>");
				return;
			}
			const result = handleClarify(message, state(), config);
			set(result.state);
			cmdCtx.ui.notify(result.message);
		},
	});

	// /go command
	pi.registerCommand("go", {
		description: "Start execution of the current plan",
		async handler(_args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const result = handleGo(state(), config);
			set(result.state);
			cmdCtx.ui.notify(result.message);
		},
	});
}

import type { ExtensionAPI, ExtensionContext, ToolResultEvent } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { detectLanguages } from "../servers/registry.ts";
import { LSPClientPool } from "../client/manager.ts";
import { syncContent, getBufferTracker } from "../sync/content-sync.ts";
import { registerLspTools } from "./tool-registry.ts";
import { pathToUri } from "../client/client.ts";
import { waitForDiagnostics } from "../features/diagnostics.ts";

export function registerPiLsp(pi: ExtensionAPI): void {
	let pool: LSPClientPool | undefined;
	let currentCtx: ExtensionContext | undefined;

	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		pool = new LSPClientPool(ctx.cwd, config.idleTimeoutMs, config.customServers);

		// Register tools
		registerLspTools(pi, pool);

		// Auto-start detected language servers
		if (config.autoStart) {
			const languages = detectLanguages(ctx.cwd);
			for (const lang of languages) {
				pool.getOrCreate(lang).catch((error: unknown) => {
					const message = error instanceof Error ? error.message : String(error);
					try {
						ctx.ui.notify(`pi-lsp: failed to start ${lang} server: ${message}`, "warning");
					} catch {
						// UI may not be available
					}
				});
			}
		}
	});

	pi.on("session_shutdown", async () => {
		if (pool) {
			await pool.shutdownAll();
			pool = undefined;
		}
		currentCtx = undefined;
		getBufferTracker().clear();
	});

	// Auto-diagnostics hook: after edit/write tools, sync content and check diagnostics
	pi.on("tool_result", async (event) => {
		if (!pool || !currentCtx) return undefined;
		const { config } = loadConfig(currentCtx.cwd);
		if (!config.autoDiagnostics || !config.syncContent) return undefined;

		const toolResult = event as ToolResultEvent;
		if (toolResult.toolName !== "edit" && toolResult.toolName !== "write") return undefined;

		// Extract file path from the tool result input
		const input = toolResult.input as { file?: string; path?: string } | undefined;
		const filePath = input?.file ?? input?.path;
		if (!filePath) return undefined;

		// Extract text content from result
		const content = toolResult.content;
		if (!Array.isArray(content)) return undefined;

		for (const item of content) {
			if (item.type === "text" && typeof item.text === "string") {
				try {
					await syncContent(pool, filePath, item.text);
					const fileUri = pathToUri(filePath);
					const client = pool.getClientForFileSync(filePath);
					if (client) {
						const diagResult = await waitForDiagnostics(client, fileUri, 3000);
						const errors = diagResult.diagnostics.filter((d) => d.severity <= 2);
						if (errors.length > 0) {
							const diagText = errors
								.map((d) => `  Line ${d.line}: ${d.message}`)
								.join("\n");
							return {
								content: [
									...content,
									{ type: "text" as const, text: `\nвҡ пёҸ LSP issues in ${filePath}:\n${diagText}` },
								],
							};
						}
					}
				} catch {
					// Best-effort; don't block on sync failure
				}
			}
		}
		return undefined;
	});
}

import type { ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { registerReviewTools } from "./tool-registry.ts";

// Import perspectives to trigger registration side effects
import "../perspectives/security.ts";
import "../perspectives/performance.ts";
import "../perspectives/maintainability.ts";
import "../perspectives/style.ts";
import "../perspectives/testing.ts";
import "../perspectives/production.ts";

export function registerPiReview(pi: ExtensionAPI): void {
	pi.on("session_start", (_event, ctx: ExtensionContext) => {
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		// Register review tools
		registerReviewTools(pi);

		// Register slash commands
		registerReviewCommands(pi, ctx);
	});
}

function registerReviewCommands(pi: ExtensionAPI, ctx: ExtensionContext): void {
	// /review вҖ” review recent changes
	pi.registerCommand("review", {
		description: "Review code changes. Subcommands: security, performance, diff, report, file <path>",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const arg = args?.trim().toLowerCase() ?? "";
			const { ReviewOrchestrator } = await import("../review/orchestrator.ts");
			const orchestrator = new ReviewOrchestrator(ctx.cwd);
			const { formatReport } = await import("../review/report.ts");

			let output: string;

			if (arg === "security") {
				const report = await orchestrator.reviewDiff(ctx.cwd, { perspectives: ["security"] });
				output = formatReport(report);
			} else if (arg === "performance") {
				const report = await orchestrator.reviewDiff(ctx.cwd, { perspectives: ["performance"] });
				output = formatReport(report);
			} else if (arg === "diff") {
				const report = await orchestrator.reviewDiff(ctx.cwd);
				output = formatReport(report);
			} else if (arg === "report") {
				const diffReport = await orchestrator.reviewDiff(ctx.cwd);
				const report = orchestrator.generateFormattedReport(diffReport.findings, {
					format: "summary",
					groupBy: "severity",
					includeSuggestions: true,
				});
				output = formatReport(report);
			} else if (arg.startsWith("file ")) {
				const file = arg.slice(5).trim();
				if (!file) {
					output = "Usage: /review file <path>";
				} else {
					const report = await orchestrator.reviewFile(ctx.cwd, file, { file });
					output = formatReport(report);
				}
			} else {
				// Default: full review
				const report = await orchestrator.reviewDiff(ctx.cwd);
				output = formatReport(report);
			}

			cmdCtx.ui.notify(output);
		},
	});
}

import type { ExtensionAPI, ExtensionContext, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { loadConfig } from "../config.ts";
import { handleWebSearch, type WebSearchInput } from "../tools/web_search.ts";
import { handleWebFetch, type WebFetchInput } from "../tools/web_fetch.ts";
import { handleWebResearch, type WebResearchInput } from "../tools/web_research.ts";
import { CacheStore } from "../cache/store.ts";

let currentCtx: ExtensionContext | undefined;
let cacheStore: CacheStore | undefined;

function getCache(cwd: string, config: ReturnType<typeof loadConfig>): CacheStore {
	if (cacheStore && cacheStore.isOpen) return cacheStore;
	cacheStore?.close();
	cacheStore = new CacheStore(cwd, config.cache.maxSizeMB);
	cacheStore.open();
	return cacheStore;
}

const toolResult = (text: string) =>
	({ content: [{ type: "text" as const, text }], details: {} });

export function registerPiWebResearch(pi: ExtensionAPI): void {
	// в”Җв”Җ session_start в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const config = loadConfig(ctx.cwd);
		if (!config.enabled) return;

		// Initialize cache
		if (config.cache.enabled) {
			try {
				const cache = getCache(ctx.cwd, config);
				cache.cleanExpired();
				cache.evictIfNeeded();
			} catch { /* non-critical */ }
		}
	});

	// в”Җв”Җ session_shutdown в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
	pi.on("session_shutdown", () => {
		cacheStore?.close();
		cacheStore = undefined;
		currentCtx = undefined;
	});

	// в”Җв”Җ Register tools в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

	const webSearchTool: ToolDefinition = {
		name: "web_search",
		label: "Web Search",
		description: "Search the web using Brave, Gemini, Exa, or DuckDuckGo. Falls back automatically if a provider is unavailable.",
		parameters: Type.Object({
			query: Type.String({ description: "Search query" }),
			maxResults: Type.Optional(Type.Number({ description: "Maximum results to return (default: 5)" })),
			engine: Type.Optional(Type.String({ description: 'Engine: "auto" | "brave" | "gemini" | "exa" | "duckduckgo"' })),
			recency: Type.Optional(Type.String({ description: 'Recency filter: "day" | "week" | "month" | "year" | "all"' })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const config = loadConfig(cwd);
			const result = await handleWebSearch(params as unknown as WebSearchInput, config);
			if (result.error) {
				return toolResult(`Search completed with issues: ${result.error}\n\nResults: ${JSON.stringify(result.results, null, 2)}`);
			}
			return toolResult(JSON.stringify(result.results, null, 2));
		},
	};

	const webFetchTool: ToolDefinition = {
		name: "web_fetch",
		label: "Web Fetch",
		description: "Fetch and extract content from a URL. Supports text, HTML, and markdown extraction with token budget enforcement.",
		parameters: Type.Object({
			url: Type.String({ description: "URL to fetch" }),
			maxTokens: *** description: "Maximum tokens in response (default: 5000)" })),
			extract: Type.Optional(Type.String({ description: 'Extraction format: "text" | "html" | "markdown"' })),
			selector: Type.Optional(Type.String({ description: "CSS selector for targeted extraction" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const config = loadConfig(cwd);
			const cache = config.cache.enabled ? getCache(cwd, config) : undefined;
			const result = await handleWebFetch(params as unknown as WebFetchInput, config, cache);
			if (result.error) {
				return toolResult(`Fetch failed: ${result.error}`);
			}
			const header = `# ${result.title}\nURL: ${result.url}${result.truncated ? " [TRUNCATED]" : ""}${result.fromCache ? " [FROM CACHE]" : ""}\n\n`;
			return toolResult(header + result.content);
		},
	};

	const webResearchTool: ToolDefinition = {
		name: "web_research",
		label: "Web Research",
		description: "Deep research mode: search, fetch, extract, and synthesize information from multiple sources into a comprehensive report.",
		parameters: Type.Object({
			query: Type.String({ description: "Research query" }),
			depth: Type.Optional(Type.String({ description: 'Research depth: "quick" | "standard" | "deep"' })),
			maxSources: Type.Optional(Type.Number({ description: "Maximum sources to analyze (default: varies by depth)" })),
		}) as never,
		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const cwd = currentCtx?.cwd ?? process.cwd();
			const config = loadConfig(cwd);
			const cache = config.cache.enabled ? getCache(cwd, config) : undefined;
			const result = await handleWebResearch(params as unknown as WebResearchInput, config, cache);
			if (result.error) {
				return toolResult(`Research encountered errors: ${result.error}\n\n${result.text}`);
			}
			return toolResult(result.text);
		},
	};

	for (const tool of [webSearchTool, webFetchTool, webResearchTool]) {
		try {
			pi.registerTool(tool);
		} catch { /* tool registration may not be available */ }
	}

	// в”Җв”Җ Register commands в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

	try {
		pi.registerCommand("research", {
			description: "Start interactive research mode on a topic",
			async handler(args: string) {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const config = loadConfig(cwd);
				const cache = config.cache.enabled ? getCache(cwd, config) : undefined;
				const query = args.trim();
				if (!query) return;
				const result = await handleWebResearch({ query, depth: "standard" }, config, cache);
				// Commands write output via context, but we'll just invoke the handler
			},
		});
	} catch { /* command registration may not be available */ }

	try {
		pi.registerCommand("web", {
			description: "Web research commands: search, cache clear",
			async handler(args: string) {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const config = loadConfig(cwd);

				const parts = args.trim().split(/\s+/);
				const subcommand = parts[0] ?? "";
				if (subcommand === "cache") {
					const action = parts[1] ?? "";
					if (action === "clear") {
						if (!cacheStore?.isOpen) return;
						cacheStore.clear();
						return;
					}
					return;
				}

				if (subcommand === "search") {
					const query = parts.slice(1).join(" ");
					if (!query) return;
					await handleWebSearch({ query }, config);
					return;
				}

				return;
			},
		});
	} catch { /* command registration may not be available */ }
}

import type { ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
