function registerVisualCommands(pi: ExtensionAPI, _ctx: ExtensionContext, state: VisualState): void {
	pi.registerCommand("visual", {
		description: "Visual overlays. Subcommands: plan, diff, architecture, progress",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const subcommand = args?.trim().toLowerCase().split(/\s+/)[0] ?? "";

			switch (subcommand) {
				case "plan": {
					const { PlanOverlay } = await import("../plan/plan-overlay.ts");
					const overlay = new PlanOverlay(state);
					const lines = overlay.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				case "diff": {
					const { DiffOverlay } = await import("../diff/diff-overlay.ts");
					const overlay = new DiffOverlay(state);
					const lines = overlay.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				case "architecture": {
					const { ArchOverlay } = await import("../architecture/arch-overlay.ts");
					const overlay = new ArchOverlay(state);
					const lines = overlay.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				case "progress": {
					const { ProgressWidget } = await import("../progress/progress-widget.ts");
					const widget = new ProgressWidget(state);
					const lines = widget.render(80);
					cmdCtx.ui.notify(lines.join("\n"));
					break;
				}
				default:
					cmdCtx.ui.notify(
						"Usage: /visual <plan|diff|architecture|progress>\n" +
						"  plan        вҖ” Open plan review overlay\n" +
						"  diff        вҖ” Open diff review overlay\n" +
						"  architecture вҖ” Open architecture view\n" +
						"  progress    вҖ” Show task progress widget",
					);
			}
		},
	});
}

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { DebugSessionManager } from "../client/manager.ts";
import { registerDebugTools } from "./tool-registry.ts";
import { Session } from "../client/session.ts";
import { Connection, type ConnectionEvents } from "../client/connection.ts";
import type { AdapterConfig } from "../types.ts";
import { AdapterRegistry } from "../adapters/registry.ts";

export function registerPiDebug(pi: ExtensionAPI): void {
	let manager: DebugSessionManager | undefined;
	let registry: AdapterRegistry | undefined;
	let currentCtx: ExtensionContext | undefined;

	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		manager = new DebugSessionManager(ctx.cwd);
		registry = new AdapterRegistry(config.adapters);

		registerDebugTools(pi, manager, registry, config);
	});

	pi.on("session_shutdown", async () => {
		if (manager) {
			await manager.stopAll();
			manager = undefined;
		}
		registry = undefined;
		currentCtx = undefined;
	});
}

/**
 * Helper: spawn a debug adapter and create a fully wired Session.
 */
export async function spawnSession(
	manager: DebugSessionManager,
	adapter: AdapterConfig,
	program: string,
	options: {
		args?: string[];
		env?: Record<string, string>;
		stopOnEntry?: boolean;
		cwd?: string;
		timeout?: number;
	},
): Promise<Session> {
	const connection = new Connection({
		onResponse: () => {},
		onEvent: (method, params) => {
			session.handleEvent(method, params);
		},
		onError: (error) => {
			void error;
		},
		onClose: () => {},
	} satisfies ConnectionEvents);

	const sessionId = `debug_${Date.now()}`;
	const session = new Session(
		sessionId,
		connection,
		() => {},
		options.timeout,
	);

	// Start transport
	if (adapter.transport === "stdio") {
		connection.startStdio(adapter.command, options.cwd ?? process.cwd(), options.env);
	} else if (adapter.transport === "tcp") {
		const port = adapter.port ?? 0;
		const host = adapter.host ?? "127.0.0.1";
		await connection.connectTcp(host, port);
	}

	// Initialize DAP handshake
	await session.start({
		program,
		args: options.args,
		env: options.env,
		stopOnEntry: options.stopOnEntry,
		cwd: options.cwd,
		adapterId: adapter.adapter,
		timeout: options.timeout,
	});

	manager.registerSession(session);
	return session;
}

export interface Filter {
	name: string;
	apply(text: string): string;
}

export interface PipelineMetrics {
	bytesIn: number;
	bytesOut: number;
	reductionPct: number;
	filtersApplied: number;
}

export function applyPipeline(text: string, filters: Filter[]): { result: string; metrics: PipelineMetrics } {
	const bytesIn = Buffer.byteLength(text, "utf-8");
	let result = text;
	let filtersApplied = 0;

	for (const filter of filters) {
		try {
			const before = result;
			result = filter.apply(result);
			if (result !== before) filtersApplied++;
		} catch (error: unknown) {
			// SAFETY: If filter fails, skip it (rtk fallback pattern)
			console.error(`[pi-smart] filter "${filter.name}" error: ${error instanceof Error ? error.message : String(error)}`);
			continue;
		}
	}

	const bytesOut = Buffer.byteLength(result, "utf-8");
	const reductionPct = bytesIn > 0 ? Math.round(((bytesIn - bytesOut) / bytesIn) * 100) : 0;

	return {
		result,
		metrics: { bytesIn, bytesOut, reductionPct, filtersApplied },
	};
}

import type { Filter } from "../pipeline.ts";

const ANSI_REGEX = /\x1b\[[0-9;]*[a-zA-Z]/g;

export function createStripAnsiFilter(): Filter {
	return {
		name: "strip-ansi",
		apply(text: string): string {
			return text.replace(ANSI_REGEX, "");
		},
	};
}

import type { Filter } from "../pipeline.ts";

export function createCompactJsonFilter(): Filter {
	return {
		name: "compact-json",
		apply(text: string): string {
			// Try to detect and compact JSON blocks in the text
			return text.replace(/```(?:json)?\s*\n([\s\S]*?)```/g, (_match: string, jsonContent: string) => {
				try {
					const parsed: unknown = JSON.parse(jsonContent);
					const compacted = JSON.stringify(parsed, null, 2);
					// If compacted is large, truncate arrays/objects >20 items
					const limited = limitJsonObj(parsed);
					if (limited !== null) {
						return "```json\n" + JSON.stringify(limited, null, 2) + "\n```";
					}
					return "```json\n" + compacted + "\n```";
				} catch {
					return _match;
				}
			});
		},
	};
}

function limitJsonObj(obj: unknown, depth: number = 0): unknown {
	if (depth > 10) return obj;
	if (Array.isArray(obj)) {
		if (obj.length > 20) {
			return [...obj.slice(0, 10), `... ${obj.length - 20} items omitted ...`, ...obj.slice(-10)];
		}
		return obj.map((item) => limitJsonObj(item, depth + 1));
	}
	if (obj !== null && typeof obj === "object") {
		const entries = Object.entries(obj as Record<string, unknown>);
		if (entries.length > 20) {
			const result: Record<string, unknown> = {};
			for (let i = 0; i < 10; i++) {
				const entry = entries[i];
				if (entry) result[entry[0]] = limitJsonObj(entry[1], depth + 1);
			}
			result["..."] = `${entries.length - 20} keys omitted`;
			for (let i = entries.length - 10; i < entries.length; i++) {
				const entry = entries[i];
				if (entry) result[entry[0]] = limitJsonObj(entry[1], depth + 1);
			}
			return result;
		}
		const result: Record<string, unknown> = {};
		for (const [k, v] of entries) {
			result[k] = limitJsonObj(v, depth + 1);
		}
		return result;
	}
	return obj;
}

import type { Filter } from "../pipeline.ts";

export function createHeadTailFilter(maxLines?: number): Filter {
	const limit = maxLines ?? 100;
	return {
		name: `head-tail:${limit}`,
		apply(text: string): string {
			const lines = text.split("\n");
			if (lines.length <= limit * 2) return text;
			const head = lines.slice(0, limit);
			const tail = lines.slice(-limit);
			const omitted = lines.length - limit * 2;
			return [...head, `[... ${omitted} lines truncated ...]`, ...tail].join("\n");
		},
	};
}

import type { Usage } from "./tracker.ts";

export interface ModelPricing {
	model: string;
	inputPerMillion: number;
	outputPerMillion: number;
	cacheReadPerMillion?: number;
	cacheWritePerMillion?: number;
}

const BUILTIN_PRICING: ModelPricing[] = [
	{ model: "claude-sonnet-4", inputPerMillion: 3, outputPerMillion: 15 },
	{ model: "claude-opus-4", inputPerMillion: 15, outputPerMillion: 75 },
	{ model: "claude-haiku-3.5", inputPerMillion: 0.8, outputPerMillion: 4 },
	{ model: "gpt-4.1", inputPerMillion: 2, outputPerMillion: 8 },
	{ model: "gpt-4o", inputPerMillion: 2.5, outputPerMillion: 10 },
	{ model: "gpt-4o-mini", inputPerMillion: 0.15, outputPerMillion: 0.6 },
	{ model: "gemini-2.5-pro", inputPerMillion: 1.25, outputPerMillion: 10 },
	{ model: "gemini-2.5-flash", inputPerMillion: 0.15, outputPerMillion: 0.6 },
];

export class PricingDatabase {
	private pricing: ModelPricing[];

	constructor(customPricing?: Record<string, { inputPerMillion?: number; outputPerMillion?: number; cacheReadPerMillion?: number; cacheWritePerMillion?: number }>) {
		this.pricing = [...BUILTIN_PRICING];

		// Merge custom pricing
		if (customPricing) {
			for (const [model, rates] of Object.entries(customPricing)) {
				if (rates.inputPerMillion !== undefined && rates.outputPerMillion !== undefined) {
					this.pricing.push({
						model,
						inputPerMillion: rates.inputPerMillion,
						outputPerMillion: rates.outputPerMillion,
						cacheReadPerMillion: rates.cacheReadPerMillion,
						cacheWritePerMillion: rates.cacheWritePerMillion,
					});
				}
			}
		}
	}

	findPricing(model: string): ModelPricing | null {
		// Exact match first
		const exact = this.pricing.find((p) => p.model === model);
		if (exact) return exact;

		// Prefix match (handles versioned models like "claude-sonnet-4-20250514")
		for (const p of this.pricing) {
			if (model.startsWith(p.model)) return p;
		}

		return null;
	}

	calculateCost(model: string, usage: Usage): number {
		const pricing = this.findPricing(model);
		if (!pricing) return 0;

		const inputCost = (usage.inputTokens / 1_000_000) * pricing.inputPerMillion;
		const outputCost = (usage.outputTokens / 1_000_000) * pricing.outputPerMillion;
		const cacheReadCost = usage.cacheReadTokens ? (usage.cacheReadTokens / 1_000_000) * (pricing.cacheReadPerMillion ?? pricing.inputPerMillion * 0.1) : 0;
		const cacheWriteCost = usage.cacheWriteTokens ? (usage.cacheWriteTokens / 1_000_000) * (pricing.cacheWritePerMillion ?? pricing.inputPerMillion * 1.25) : 0;

		return inputCost + outputCost + cacheReadCost + cacheWriteCost;
	}
}

import * as fs from "node:fs";
import * as path from "node:path";
import BetterSqlite3 from "better-sqlite3";
import type Database from "better-sqlite3";
import { initSchema } from "./schema.ts";

/**
 * Manages the SQLite database connection for pi-memory.
 * Database is stored at <cwd>/.pi-memory/memory.db.
 */
export class MemoryDB {
	public readonly cwd: string;
	public readonly dbPath: string;
	private db: Database.Database | null = null;

	constructor(cwd: string) {
		this.cwd = cwd;
		const dir = path.join(cwd, ".pi-memory");
		fs.mkdirSync(dir, { recursive: true });
		this.dbPath = path.join(dir, "memory.db");
	}

	/** Open (or return existing) database connection with full schema. */
	open(): Database.Database {
		if (this.db) return this.db;
		this.db = new BetterSqlite3(this.dbPath) as unknown as Database.Database;
		initSchema(this.db);
		return this.db;
	}

	/** Get the current open connection (throws if not open). */
	getConnection(): Database.Database {
		if (!this.db) throw new Error("MemoryDB not opened. Call open() first.");
		return this.db;
	}

	/** Close the database connection. */
	close(): void {
		if (this.db) {
			try {
				this.db.close();
			} catch {
				// Ignore close errors
			}
			this.db = null;
		}
	}

	/** Check if the database is currently open. */
	get isOpen(): boolean {
		return this.db !== null;
	}
}

