import type { WebResearchConfig, ExtractedContent, ExtractOptions } from "../types.ts";
import { fetchUrl } from "../extract/fetcher.ts";
import { extractContent } from "../extract/extractor.ts";
import { parseGitHubUrl, extractGitHub } from "../extract/github.ts";
import { enforceBudget } from "../extract/budget.ts";
import type { CacheStore } from "../cache/store.ts";

export interface WebFetchInput {
	url: string;
	maxTokens?: number;
	extract?: "text" | "html" | "markdown";
	selector?: string;
}

export interface WebFetchOutput {
	title: string;
	url: string;
	content: string;
	contentType: string;
	contentLength: number;
	truncated: boolean;
	fromCache: boolean;
	error?: string;
}

export async function handleWebFetch(
	input: WebFetchInput,
	config: WebResearchConfig,
	cache?: CacheStore,
): Promise<WebFetchOutput> {
	const url = input.url;
	const maxTokens = *** ?? config.fetch.maxTokens;
	const format = input.extract ?? "text";

	// Check cache first
	if (cache?.isOpen && config.cache.enabled) {
		const cached = cache.get(url);
		if (cached) {
			const budget = enforceBudget(cached.content, maxTokens);
			return {
				title: url,
				url,
				content: budget.content,
				contentType: format,
				contentLength: budget.finalLength,
				truncated: budget.truncated,
				fromCache: true,
			};
		}
	}

	// GitHub special handling
	const ghParsed = parseGitHubUrl(url);
	if (ghParsed) {
		try {
			const ghContent = await extractGitHub(url, { maxTokens, format });
			if (cache?.isOpen && config.cache.enabled) {
				const ttl = config.cache.maxAgeHours * 60 * 60 * 1000;
				cache.set(url, ghContent.content, "text/plain", ttl);
			}
			return {
				title: ghContent.title,
				url: ghContent.url,
				content: ghContent.content,
				contentType: format,
				contentLength: ghContent.content.length,
				truncated: (ghContent.metadata?.truncated as boolean) ?? false,
				fromCache: false,
			};
		} catch (err) {
			return {
				title: url,
				url,
				content: "",
				contentType: format,
				contentLength: 0,
				truncated: false,
				fromCache: false,
				error: `GitHub extraction failed: ${err instanceof Error ? err.message : String(err)}`,
			};
		}
	}

	// Regular fetch
	try {
		const fetched = await fetchUrl(url, config);
		const extracted = extractContent(fetched.content, fetched.url, {
			maxTokens,
			format,
			selector: input.selector,
		});

		// Cache the raw fetched content
		if (cache?.isOpen && config.cache.enabled) {
			const ttl = config.cache.maxAgeHours * 60 * 60 * 1000;
			cache.set(url, fetched.content, fetched.contentType, ttl);
		}

		return {
			title: extracted.title,
			url: extracted.url,
			content: extracted.content,
			contentType: extracted.contentType,
			contentLength: extracted.contentLength,
			truncated: extracted.truncated,
			fromCache: false,
		};
	} catch (err) {
		return {
			title: url,
			url,
			content: "",
			contentType: format,
			contentLength: 0,
			truncated: false,
			fromCache: false,
			error: `Fetch failed: ${err instanceof Error ? err.message : String(err)}`,
		};
	}
}

import * as crypto from "node:crypto";
import type Database from "better-sqlite3";
import { getSessionEvents } from "../store/events.ts";
import { routeSessionFindings, type RoutedFinding } from "./router.ts";
import { extractBugSolution, extractDecision, extractKnowledge, type Solution } from "./extractor.ts";
import { findPotentialDuplicates, assessOverlap, shouldDedup, type SolutionForDedup } from "./dedup.ts";
import { writeSolution } from "./writer.ts";
import { indexContent } from "../store/fts5-index.ts";

export interface AnalysisResult {
	solutionsFound: number;
	solutionsWritten: number;
	duplicatesMerged: number;
}

/**
 * Analyze a session at shutdown time:
 * 1. Extract findings from session events
 * 2. Route findings to bug/knowledge/decision types
 * 3. Dedup against existing solutions
 * 4. Write new solutions
 */
export function analyzeSession(
	db: Database.Database,
	cwd: string,
	sessionId: string,
	dedupThreshold: number = 0.7,
): AnalysisResult {
	const events = getSessionEvents(db, sessionId);
	if (events.length === 0) return { solutionsFound: 0, solutionsWritten: 0, duplicatesMerged: 0 };

	const findings = routeSessionFindings(events);
	let solutionsFound = 0;
	let solutionsWritten = 0;
	let duplicatesMerged = 0;

	for (const finding of findings) {
		const solution = extractSolution(finding);
		if (!solution) continue;
		solutionsFound++;

		const title = buildTitle(finding, finding.events);
		const solForDedup: SolutionForDedup = {
			title,
			content: solutionContent(solution),
			files: solution.files,
			tags: solution.tags,
		};

		// Check for duplicates
		const dupes = findPotentialDuplicates(db, title);
		let isDuplicate = false;
		for (const dupe of dupes) {
			const dupeForCompare: SolutionForDedup = {
				title: dupe.title,
				content: dupe.content,
				files: dupe.files ? JSON.parse(dupe.files) as string[] : [],
				tags: dupe.tags ? JSON.parse(dupe.tags) as string[] : [],
			};
			const overlap = assessOverlap(solForDedup, dupeForCompare);
			if (shouldDedup(overlap, dedupThreshold)) {
				isDuplicate = true;
				duplicatesMerged++;
				// Increment access count on the existing solution
				db.prepare(
					`UPDATE solutions SET access_count = access_count + 1, last_accessed_at = ? WHERE title = ?`,
				).run(new Date().toISOString(), dupe.title);
				break;
			}
		}

		if (!isDuplicate) {
			writeSolutionToDb(db, title, solution);
			writeSolution(cwd, solution, title);
			solutionsWritten++;
		}
	}

	return { solutionsFound, solutionsWritten, duplicatesMerged };
}

function extractSolution(finding: RoutedFinding): Solution | null {
	const events = finding.events;
	switch (finding.type) {
		case "bug": {
			const error = events.find((e) => e.type === "error");
			const fix = events.find((e) => e.type === "command_success") ?? null;
			if (!error) return null;
			return extractBugSolution(error, fix);
		}
		case "decision": {
			const decision = events.find((e) => e.type === "user_decision");
			if (!decision) return null;
			return extractDecision(decision);
		}
		case "knowledge":
			return extractKnowledge(events);
		default:
			return null;
	}
}

function buildTitle(finding: RoutedFinding, events: typeof finding.events): string {
	switch (finding.type) {
		case "bug": {
			const error = events.find((e) => e.type === "error");
			if (!error) return "Unknown bug";
			try {
				const data = JSON.parse(error.data) as Record<string, unknown>;
				const msg = typeof data.errorMessage === "string" ? data.errorMessage : "error";
				return msg.slice(0, 80);
			} catch {
				return "Unknown bug";
			}
		}
		case "decision": {
			const d = events.find((e) => e.type === "user_decision");
			if (!d) return "Decision";
			try {
				const data = JSON.parse(d.data) as Record<string, unknown>;
				return typeof data.message_summary === "string" ? data.message_summary.slice(0, 80) : "Decision";
			} catch {
				return "Decision";
			}
		}
		case "knowledge": {
			const files = events
				.map((e) => { try { return (JSON.parse(e.data) as Record<string, unknown>).file as string; } catch { return ""; } })
				.filter((f) => f.length > 0);
			return files.length > 0 ? `Pattern: ${files.join(", ")}` : "Knowledge pattern";
		}
		default:
			return "Unknown finding";
	}
}

function solutionContent(solution: Solution): string {
	switch (solution.type) {
		case "bug": return `${solution.problem}\n${solution.rootCause}\n${solution.fix}`;
		case "knowledge": return `${solution.whenToUse}\n${solution.how}`;
		case "decision": return `${solution.context}\n${solution.reasoning}`;
	}
}

function writeSolutionToDb(db: Database.Database, title: string, solution: Solution): void {
	const id = crypto.randomUUID();
	const now = new Date().toISOString();
	const content = solutionContent(solution);
	const overlapHash = crypto.createHash("sha256").update(title + content).digest("hex");

	db.prepare(`
		INSERT INTO solutions (id, problem_type, category, title, content, files, tags, severity, overlap_hash, created_at, updated_at)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
	`).run(
		id,
		solution.type,
		solution.type,
		title,
		content,
		JSON.stringify(solution.files),
		JSON.stringify(solution.tags),
		"medium",
		overlapHash,
		now,
		now,
	);

	// Index for search
	indexContent(db, id, title, content, solution.type);
}

import type { WebResearchConfig } from "../types.ts";

export interface FetchResult {
	url: string;
	content: string;
	contentType: string; // "text/html", "text/plain", "application/json", etc.
	statusCode: number;
}

/**
 * Fetch raw content from a URL.
 * Uses Node.js built-in fetch with configurable timeout and User-Agent.
 */
export async function fetchUrl(
	url: string,
	config: WebResearchConfig,
): Promise<FetchResult> {
	const controller = new AbortController();
	const timer = setTimeout(() => controller.abort(), config.fetch.timeout);

	try {
		const response = await fetch(url, {
			headers: {
				"User-Agent": config.fetch.userAgent,
				"Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,text/plain;q=0.8,application/json;q=0.7,*/*;q=0.1",
				"Accept-Encoding": "gzip, deflate",
			},
			redirect: "follow",
			signal: controller.signal,
		});

		const contentType = response.headers.get("content-type") ?? "text/plain";
		const content = await response.text();

		return {
			url: response.url, // Final URL after redirects
			content,
			contentType,
			statusCode: response.status,
		};
	} finally {
		clearTimeout(timer);
	}
}

// LAZY: linkedom is heavy вҖ” only imported when actually needed for HTML parsing
import { parseHTML } from "linkedom";
import type { ExtractedContent, ExtractOptions } from "../types.ts";
import { enforceBudget } from "./budget.ts";

/** Noise elements to strip from HTML before extraction. */
const NOISE_SELECTORS = [
	"script", "style", "nav", "footer", "header",
	".ad", ".ads", ".advertisement", ".sidebar", ".popup",
	".cookie-banner", ".social-share", ".newsletter",
	"[role='navigation']", "[role='banner']", "[role='contentinfo']",
];

/**
 * Extract meaningful content from raw HTML.
 * 1. Parse HTML with linkedom
 * 2. Remove noise elements
 * 3. Apply CSS selector if provided, otherwise find main content
 * 4. Convert to requested format
 * 5. Enforce token budget
 */
export function extractContent(
	html: string,
	url: string,
	opts: ExtractOptions = {},
): ExtractedContent {
	const format = opts.format ?? "text";
	const maxTokens = *** ?? 5000;

	const { document } = parseHTML(html);

	// Extract title
	const titleEl = document.querySelector("title");
	const title = titleEl?.textContent?.trim() ?? url;

	// Remove noise
	for (const selector of NOISE_SELECTORS) {
		try {
			const elements = document.querySelectorAll(selector);
			for (const el of elements) {
				el.parentNode?.removeChild(el);
			}
		} catch {
			// Invalid selector вҖ” skip
		}
	}

	let contentElement: globalThis.Element | null;

	// If a CSS selector is provided, use it
	if (opts.selector) {
		contentElement = document.querySelector(opts.selector);
		if (!contentElement) {
			// Fallback to body
			contentElement = document.querySelector("body") ?? document.documentElement;
		}
	} else {
		// Find main content via heuristic
		contentElement = findMainContent(document);
	}

	// Convert to requested format
	let content: string;
	switch (format) {
		case "html":
			content = contentElement?.innerHTML ?? "";
			break;
		case "markdown":
			content = htmlToMarkdown(contentElement?.innerHTML ?? "");
			break;
		case "text":
		default:
			content = contentElement?.textContent ?? "";
			break;
	}

	// Clean up whitespace
	content = content.replace(/\n{3,}/g, "\n\n").replace(/[ \t]+/g, " ").trim();

	// Enforce budget
	const budgetResult = enforceBudget(content, maxTokens);

	return {
		title,
		url,
		content: budgetResult.content,
		contentType: format,
		contentLength: budgetResult.finalLength,
		truncated: budgetResult.truncated,
	};
}

/**
 * Find the main content element using heuristics:
 * 1. Look for <article>, <main>, or role="main"
 * 2. Look for the element with the most text content
 */
function findMainContent(document: globalThis.Document): globalThis.Element {
	// Try semantic elements first
	const candidates = [
		document.querySelector("article"),
		document.querySelector("main"),
		document.querySelector("[role='main']"),
		document.querySelector(".post-content"),
		document.querySelector(".article-content"),
		document.querySelector(".entry-content"),
		document.querySelector(".content"),
	];

	for (const el of candidates) {
		if (el && (el.textContent?.length ?? 0) > 100) {
			return el;
		}
	}

	// Fallback: find the div/section with the most text
	const body = document.querySelector("body") ?? document.documentElement;
	let best = body as globalThis.Element;
	let bestLen = body.textContent?.length ?? 0;

	const divs = body.querySelectorAll("div, section");
	for (const div of divs) {
		const len = div.textContent?.length ?? 0;
		if (len > bestLen) {
			bestLen = len;
			best = div;
		}
	}

	return best;
}

/**
 * Minimal HTML to Markdown conversion.
 * Handles headings, paragraphs, lists, links, bold, italic, code.
 */
export function htmlToMarkdown(html: string): string {
	let md = html;

	// Headings
	md = md.replace(/<h([1-6])[^>]*>([\s\S]*?)<\/h\1>/gi, (_match, level: string, content: string) => {
		const hashes = "#".repeat(Number(level));
		return `\n${hashes} ${content.trim()}\n`;
	});

	// Paragraphs
	md = md.replace(/<p[^>]*>([\s\S]*?)<\/p>/gi, "\n$1\n");

	// Links
	md = md.replace(/<a[^>]+href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/gi, "[$2]($1)");

	// Bold
	md = md.replace(/<(strong|b)[^>]*>([\s\S]*?)<\/\1>/gi, "**$2**");

	// Italic
	md = md.replace(/<(em|i)[^>]*>([\s\S]*?)<\/\1>/gi, "*$2*");

	// Code blocks
	md = md.replace(/<pre[^>]*><code[^>]*>([\s\S]*?)<\/code><\/pre>/gi, "\n```\n$1\n```\n");
	md = md.replace(/<code[^>]*>([\s\S]*?)<\/code>/gi, "`$1`");

	// List items
	md = md.replace(/<li[^>]*>([\s\S]*?)<\/li>/gi, "- $1");

	// Line breaks
	md = md.replace(/<br\s*\/?>/gi, "\n");

	// Strip remaining tags
	md = md.replace(/<[^>]+>/g, "");

	// Decode entities
	md = md.replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">")
		.replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, " ");

	// Clean whitespace
	md = md.replace(/\n{3,}/g, "\n\n").trim();

	return md;
}

import { Connection, type ConnectionEvents } from "./connection.ts";
import { Lifecycle } from "./lifecycle.ts";
import { LSPClientState, type LSPClientStateValue, type Diagnostic } from "../types.ts";

export class LSPClient {
	private conn: Connection;
	private lifecycle: Lifecycle;
	private diagnosticsMap = new Map<string, Diagnostic[]>();
	private state: LSPClientStateValue = LSPClientState.Stopped;
	private lastActivityAt = Date.now();
	private language: string;
	private cwd: string;

	constructor(language: string, cwd: string) {
		this.language = language;
		this.cwd = cwd;
		const events: ConnectionEvents = {
			onResponse: () => {},
			onNotification: (method, params) => this.handleNotification(method, params),
			onError: () => {},
			onClose: () => {
				this.state = LSPClientState.Stopped;
			},
		};
		this.conn = new Connection(events);
		const rootUri = pathToUri(cwd);
		this.lifecycle = new Lifecycle(this.conn, rootUri);
	}

	get clientState(): LSPClientStateValue {
		return this.state;
	}

	get lastActivity(): number {
		return this.lastActivityAt;
	}

	getDiagnostics(fileUri: string): Diagnostic[] {
		return this.diagnosticsMap.get(fileUri) ?? [];
	}

	getAllDiagnostics(): Map<string, Diagnostic[]> {
		return new Map(this.diagnosticsMap);
	}

	async start(command: string[]): Promise<void> {
		if (this.state !== LSPClientState.Stopped) return;
		this.conn.start(command, this.cwd);
		await this.lifecycle.initialize();
		this.state = LSPClientState.Ready;
		this.lastActivityAt = Date.now();
	}

	async shutdown(): Promise<void> {
		if (this.state !== LSPClientState.Ready) {
			this.conn.kill();
			return;
		}
		await this.lifecycle.shutdown();
		this.conn.kill();
		this.state = LSPClientState.Stopped;
	}

	async sendRequest(method: string, params?: unknown): Promise<unknown> {
		if (this.state !== LSPClientState.Ready) {
			throw new Error(`Client not ready (state=${this.state})`);
		}
		this.lastActivityAt = Date.now();
		return this.conn.sendRequest(method, params);
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.state !== LSPClientState.Ready) return;
		this.lastActivityAt = Date.now();
		this.conn.sendNotification(method, params);
	}

	private handleNotification(method: string, params: unknown): void {
		if (method === "textDocument/publishDiagnostics") {
			const p = params as { uri?: string; diagnostics?: Diagnostic[] };
			if (typeof p.uri === "string") {
				this.diagnosticsMap.set(p.uri, p.diagnostics ?? []);
			}
		}
	}
}

export function pathToUri(filePath: string): string {
	const absolute = filePath.startsWith("/") ? filePath : filePath;
	return `file://${absolute}`;
}

export function uriToPath(uri: string): string {
	return uri.replace(/^file:\/\//, "");
}

import { ChildProcess, spawn } from "node:child_process";
import type { JsonRpcRequest, JsonRpcNotification, JsonRpcResponse } from "../types.ts";

export interface ConnectionEvents {
	onResponse: (msg: JsonRpcResponse) => void;
	onNotification: (method: string, params: unknown) => void;
	onError: (error: Error) => void;
	onClose: () => void;
}

export class Connection {
	private proc: ChildProcess | null = null;
	private buffer = "";
	private nextId = 1;
	private pending = new Map<number | string, { resolve: (value: unknown) => void; reject: (error: Error) => void }>();
	private handlers: ConnectionEvents;
	private closed = false;

	constructor(handlers: ConnectionEvents) {
		this.handlers = handlers;
	}

	get isClosed(): boolean {
		return this.closed;
	}

	start(command: string[], cwd: string): void {
		this.proc = spawn(command[0], command.slice(1), {
			cwd,
			stdio: ["pipe", "pipe", "pipe"],
		});

		this.proc.stdout?.on("data", (chunk: Buffer) => {
			this.buffer += chunk.toString("utf-8");
			this.parseMessages();
		});

		this.proc.stderr?.on("data", (chunk: Buffer) => {
			// LSP servers log to stderr; ignore or forward
			void chunk;
		});

		this.proc.on("error", (err) => {
			this.handlers.onError(err);
		});

		this.proc.on("close", () => {
			this.closed = true;
			for (const [id, pending] of this.pending) {
				pending.reject(new Error(`Connection closed (pending request ${id})`));
			}
			this.pending.clear();
			this.handlers.onClose();
		});
	}

	sendRequest(method: string, params?: unknown): Promise<unknown> {
		return new Promise((resolve, reject) => {
			if (this.closed || !this.proc?.stdin?.writable) {
				reject(new Error("Connection is closed"));
				return;
			}
			const id = this.nextId++;
			const msg: JsonRpcRequest = { jsonrpc: "2.0", id, method, params };
			this.pending.set(id, { resolve, reject });
			this.write(msg);
		});
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.closed || !this.proc?.stdin?.writable) return;
		const msg: JsonRpcNotification = { jsonrpc: "2.0", method, params };
		this.write(msg);
	}

	private write(msg: JsonRpcRequest | JsonRpcNotification): void {
		const body = JSON.stringify(msg);
		const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
		this.proc!.stdin!.write(header + body, "utf-8");
	}

	private parseMessages(): void {
		while (this.buffer.length > 0) {
			const headerEnd = this.buffer.indexOf("\r\n\r\n");
			if (headerEnd === -1) break;

			const header = this.buffer.substring(0, headerEnd);
			const match = header.match(/^Content-Length:\s*(\d+)/i);
			if (!match) {
				this.buffer = this.buffer.substring(headerEnd + 4);
				continue;
			}

			const contentLength = Number.parseInt(match[1], 10);
			const bodyStart = headerEnd + 4;
			const bodyEnd = bodyStart + contentLength;

			if (this.buffer.length < bodyEnd) break;

			const body = this.buffer.substring(bodyStart, bodyEnd);
			this.buffer = this.buffer.substring(bodyEnd);

			try {
				const msg = JSON.parse(body) as JsonRpcResponse;
				if ("id" in msg && ("result" in msg || "error" in msg)) {
					const pending = this.pending.get(msg.id);
					if (pending) {
						this.pending.delete(msg.id);
						if (msg.error) {
							pending.reject(new Error(`LSP error ${msg.error.code}: ${msg.error.message}`));
						} else {
							pending.resolve(msg.result);
						}
					}
					this.handlers.onResponse(msg);
				} else if ("method" in msg) {
					this.handlers.onNotification((msg as unknown as { method: string }).method, (msg as unknown as { params?: unknown }).params);
				}
			} catch {
				// Ignore malformed messages
			}
		}
	}

	kill(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection killed"));
		}
		this.pending.clear();
		this.proc?.kill();
		this.proc = null;
	}
}

import type { Filter } from "../pipeline.ts";

export function createShortenPathsFilter(projectRoot?: string): Filter {
	const root = projectRoot || process.cwd();
	const normalizedRoot = root.replace(/\\/g, "/") + "/";
	// Match Windows user paths: C:\Users\<user>\
	const winUserRegex = /^[A-Za-z]:\\Users\\[^\\]+\\/g;
	return {
		name: "shorten-paths",
		apply(text: string): string {
			let result = text;
			// Shorten project root paths
			result = result.split(normalizedRoot).join("./");
			// Shorten Windows user paths
			result = result.replace(winUserRegex, "~/");
			// Shorten remaining long paths: keep last 3 segments
			result = result.replace(/(?:\/[\w.-]+){4,}/g, (match: string) => {
				const segments = match.split("/");
				if (segments.length <= 4) return match;
				return "/.../" + segments.slice(-3).join("/");
			});
			return result;
		},
	};
}

import type Database from "better-sqlite3";

/**
 * Index content into both FTS5 tables (porter + trigram).
 */
export function indexContent(
	db: Database.Database,
	sourceId: string,
	title: string,
	content: string,
	category: string,
): void {
	// Insert into porter-stemmed FTS5 index
	const insertChunk = db.prepare(
		`INSERT INTO chunks (source_id, title, content, category) VALUES (?, ?, ?, ?)`,
	);
	insertChunk.run(sourceId, title, content, category);

	// Insert into trigram FTS5 index
	const insertTrigram = db.prepare(
		`INSERT INTO chunks_trigram (source_id, content) VALUES (?, ?)`,
	);
	insertTrigram.run(sourceId, content);
}

/**
 * Remove all indexed content for a given source from both FTS5 tables.
 */
export function removeFromIndex(db: Database.Database, sourceId: string): void {
	db.prepare(`DELETE FROM chunks WHERE source_id = ?`).run(sourceId);
	db.prepare(`DELETE FROM chunks_trigram WHERE source_id = ?`).run(sourceId);
}

