/** Lightweight markdown-to-ANSI renderer for TUI components. */

export interface MarkupTheme {
	heading: (text: string) => string;
	bold: (text: string) => string;
	dim: (text: string) => string;
	code: (text: string) => string;
	bullet: (text: string) => string;
	hr: string;
}

/** Default ANSI theme using escape codes. */
export const ANSI_THEME: MarkupTheme = {
	heading: (t) => `\x1b[1;4m${t}\x1b[0m`,
	bold: (t) => `\x1b[1m${t}\x1b[0m`,
	dim: (t) => `\x1b[2m${t}\x1b[0m`,
	code: (t) => `\x1b[36m${t}\x1b[0m`,
	bullet: (t) => `  вҖў ${t}`,
	hr: "в”Җ".repeat(60),
};

/** Plain text theme (no ANSI escapes). */
export const PLAIN_THEME: MarkupTheme = {
	heading: (t) => t,
	bold: (t) => t,
	dim: (t) => t,
	code: (t) => t,
	bullet: (t) => `  вҖў ${t}`,
	hr: "в”Җ".repeat(60),
};

/** Render a simple markdown string into styled string lines. */
export function renderMarkup(markdown: string, theme: MarkupTheme = PLAIN_THEME): string[] {
	const lines = markdown.split("\n");
	const result: string[] = [];

	let inCodeBlock = false;
	for (const line of lines) {
		if (line.startsWith("```")) {
			inCodeBlock = !inCodeBlock;
			continue;
		}
		if (inCodeBlock) {
			result.push(theme.dim(`    ${line}`));
			continue;
		}
		if (line.startsWith("### ")) {
			result.push(theme.heading(line.slice(4)));
		} else if (line.startsWith("## ")) {
			result.push(theme.heading(line.slice(3)));
		} else if (line.startsWith("# ")) {
			result.push(theme.heading(line.slice(2)));
		} else if (line.startsWith("---")) {
			result.push(theme.hr);
		} else if (line.startsWith("- ") || line.startsWith("* ")) {
			const content = applyInline(line.slice(2), theme);
			result.push(theme.bullet(content));
		} else if (line.trim() === "") {
			result.push("");
		} else {
			result.push(applyInline(line, theme));
		}
	}

	return result;
}

/** Apply inline formatting: **bold**, `code`. */
function applyInline(text: string, theme: MarkupTheme): string {
	// Bold: **text**
	let result = text.replace(/\*\*(.+?)\*\*/g, (_, content: string) => theme.bold(content));
	// Code: `text`
	result = result.replace(/`(.+?)`/g, (_, content: string) => theme.code(content));
	return result;
}

import type { SearchEngine } from "./engine.ts";
import type { SearchResult, SearchOptions } from "../types.ts";
import { BraveSearchEngine } from "./brave.ts";
import { GeminiSearchEngine } from "./gemini.ts";
import { ExaSearchEngine } from "./exa.ts";
import { DuckDuckGoSearchEngine } from "./duckduckgo.ts";

export interface FallbackChainConfig {
	/** Ordered list of engine names to try. */
	chain: string[];
	/** API keys keyed by engine name. */
	apiKeys: ***, string>;
}

/** Build an engine instance by name. */
export function createEngine(name: string, apiKeys: ***, string>): SearchEngine {
	switch (name) {
		case "brave": return new BraveSearchEngine(apiKeys.brave ?? "");
		case "gemini": return new GeminiSearchEngine(apiKeys.gemini ?? "");
		case "exa": return new ExaSearchEngine(apiKeys.exa ?? "");
		case "duckduckgo": return new DuckDuckGoSearchEngine();
		default:
			throw new Error(`Unknown search engine: ${name}`);
	}
}

/** Result when all engines in the chain fail. */
export interface FallbackFailure {
	results: SearchResult[];
	triedEngines: string[];
	suggestion: string;
}

/**
 * Execute search across engines in fallback order.
 * - Skips engines where isAvailable() returns false.
 * - If an engine throws, catches the error and tries the next.
 * - Returns results from the first successful engine.
 */
export async function fallbackSearch(
	config: FallbackChainConfig,
	query: string,
	opts?: SearchOptions,
): Promise<SearchResult[] | FallbackFailure> {
	const triedEngines: string[] = [];

	for (const engineName of config.chain) {
		let engine: SearchEngine;
		try {
			engine = createEngine(engineName, config.apiKeys);
		} catch {
			continue; // Unknown engine name, skip
		}

		if (!engine.isAvailable()) {
			continue; // No API key or not ready
		}

		triedEngines.push(engineName);
		try {
			const results = await engine.search(query, opts);
			if (results.length > 0) {
				return results;
			}
			// Empty results вҖ” try next engine
		} catch {
			// Engine error вҖ” try next
		}
	}

	// All engines failed or returned empty
	return {
		results: [],
		triedEngines,
		suggestion: "No search providers available. Set API keys in config or env vars.",
	};
}

import { existsSync } from "node:fs";
import { extname, resolve } from "node:path";
import type { AdapterConfig } from "../types.ts";
import { getBuiltinAdapters } from "./index.ts";
import { loadCustomAdapters } from "./custom.ts";

/**
 * AdapterRegistry resolves file paths to appropriate debug adapter configurations.
 * Built-in adapters can be overridden by user-configured adapters.
 */
export class AdapterRegistry {
	private adapters: AdapterConfig[] = [];
	private customAdapters: AdapterConfig[] = [];

	constructor(customConfig?: Record<string, Partial<AdapterConfig> & { enabled?: boolean }>) {
		this.adapters = getBuiltinAdapters();
		if (customConfig) {
			this.customAdapters = loadCustomAdapters(customConfig);
		}
	}

	/** Resolve an adapter for a file path based on extension. */
	resolve(filePath: string, cwd?: string): AdapterConfig | undefined {
		const ext = extname(filePath);

		// Custom adapters take priority
		const custom = this.customAdapters.find((a) =>
			a.extensions.includes(ext),
		);
		if (custom) return custom;

		// Built-in adapters
		const builtin = this.adapters.find((a) =>
			a.extensions.includes(ext),
		);
		if (builtin) return builtin;

		return undefined;
	}

	/** Resolve adapter by name. */
	getByName(name: string): AdapterConfig | undefined {
		return (
			this.customAdapters.find((a) => a.adapter === name || a.language === name) ??
			this.adapters.find((a) => a.adapter === name || a.language === name)
		);
	}

	/** Check if a detection file exists in the cwd, indicating this adapter type is relevant. */
	async detect(cwd: string): Promise<AdapterConfig[]> {
		const detected: AdapterConfig[] = [];
		const all = [...this.customAdapters, ...this.adapters];

		for (const adapter of all) {
			if (adapter.detectionFiles.length === 0) {
				detected.push(adapter);
				continue;
			}
			for (const detectionFile of adapter.detectionFiles) {
				if (existsSync(resolve(cwd, detectionFile))) {
					detected.push(adapter);
					break;
				}
			}
		}

		return detected;
	}

	/** Get all registered adapters. */
	getAll(): AdapterConfig[] {
		return [...this.customAdapters, ...this.adapters];
	}
}

import * as fs from "node:fs";
import * as path from "node:path";
import type { LspExtensionConfig, LSPServerConfig } from "./types.ts";

const DEFAULT_CONFIG: LspExtensionConfig = {
	enabled: true,
	autoStart: true,
	idleTimeoutMs: 300_000,
	syncContent: true,
	autoDiagnostics: true,
	servers: {},
	customServers: [],
};

export function loadConfig(cwd: string): { config: LspExtensionConfig; path: string } {
	const configPath = path.join(cwd, ".pi", "pi-lsp.json");
	if (!fs.existsSync(configPath)) {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed = JSON.parse(raw) as Partial<LspExtensionConfig>;
		return {
			config: {
				enabled: parsed.enabled ?? DEFAULT_CONFIG.enabled,
				autoStart: parsed.autoStart ?? DEFAULT_CONFIG.autoStart,
				idleTimeoutMs: parsed.idleTimeoutMs ?? DEFAULT_CONFIG.idleTimeoutMs,
				syncContent: parsed.syncContent ?? DEFAULT_CONFIG.syncContent,
				autoDiagnostics: parsed.autoDiagnostics ?? DEFAULT_CONFIG.autoDiagnostics,
				servers: { ...DEFAULT_CONFIG.servers, ...(parsed.servers ?? {}) },
				customServers: validateCustomServers(parsed.customServers),
			},
			path: configPath,
		};
	} catch {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
}

function validateCustomServers(servers: unknown): LSPServerConfig[] {
	if (!Array.isArray(servers)) return [];
	const valid: LSPServerConfig[] = [];
	for (const server of servers) {
		if (
			typeof server === "object" && server !== null &&
			typeof (server as Record<string, unknown>).language === "string" &&
			Array.isArray((server as Record<string, unknown>).command) &&
			Array.isArray((server as Record<string, unknown>).extensions)
		) {
			valid.push(server as LSPServerConfig);
		}
	}
	return valid;
}

import type Database from "better-sqlite3";
import { search, type SearchOptions } from "../store/search.ts";

export interface MemorySearchInput {
	query: string;
	maxResults?: number;
	scope?: "all" | "solutions" | "decisions" | "gotchas" | "conventions";
	detail?: "compact" | "medium" | "full";
}

export interface MemorySearchResult {
	results: Array<{
		title: string;
		content: string;
		category: string;
		score: number;
	}>;
	totalCount: number;
}

function formatResult(title: string, content: string, category: string, score: number, detail: string): string {
	switch (detail) {
		case "compact":
			return `${title} (${category}, score: ${score.toFixed(3)})`;
		case "medium":
			return `${title} (${category}): ${content.slice(0, 200)}`;
		case "full":
			return `## ${title}\nCategory: ${category}\n\n${content}`;
		default:
			return `${title}: ${content.slice(0, 200)}`;
	}
}

/**
 * Handle the memory_search tool invocation.
 */
export function handleMemorySearch(db: Database.Database, input: MemorySearchInput): string {
	const opts: SearchOptions = {
		maxResults: input.maxResults ?? 5,
		scope: input.scope ?? "all",
		detail: input.detail ?? "compact",
	};

	const results = search(db, input.query, opts);

	if (results.length === 0) {
		return `No results found for "${input.query}".`;
	}

	const detail = input.detail ?? "compact";
	const formatted = results
		.map((r) => formatResult(r.title, r.content, r.category, r.score, detail))
		.join("\n\n");

	return `Found ${results.length} result(s) for "${input.query}":\n\n${formatted}`;
}

import { spawn } from "node:child_process";

export interface GitDiffOptions {
	base?: string;
	head?: string;
	cwd: string;
	maxFiles?: number;
}

export async function extractDiff(options: GitDiffOptions): Promise<string> {
	const { cwd, base, head, maxFiles = 20 } = options;

	const args = ["diff", "--unified=5"];
	if (base && head) {
		args.push(`${base}...${head}`);
	} else if (base) {
		args.push(base);
	} else {
		// Default: staged + unstaged changes vs HEAD
		args.push("HEAD");
	}

	const result = await runGit(args, cwd);

	if (result.exitCode !== 0 && !result.stdout) {
		throw new Error(`git diff failed (exit ${result.exitCode}): ${result.stderr}`);
	}

	// Limit files if needed
	if (maxFiles > 0) {
		return limitFiles(result.stdout, maxFiles);
	}

	return result.stdout;
}

export async function extractFileDiff(cwd: string, file: string, base?: string): Promise<string> {
	const args = ["diff", "--unified=5"];
	if (base) {
		args.push(base);
	} else {
		args.push("HEAD");
	}
	args.push("--", file);

	const result = await runGit(args, cwd);
	return result.stdout;
}

function limitFiles(diff: string, maxFiles: number): string {
	const files: string[] = [];
	const lines = diff.split("\n");
	const output: string[] = [];
	let currentFileOutput: string[] = [];
	let inFile = false;

	for (const line of lines) {
		if (line.startsWith("diff --git")) {
			if (inFile && files.length < maxFiles) {
				output.push(...currentFileOutput);
			}
			if (files.length >= maxFiles) {
				output.push(`\n... (truncated: showing first ${maxFiles} files)`);
				return output.join("\n");
			}
			const match = line.match(/^diff --git a\/(.+?) b\/(.+)$/);
			if (match) {
				files.push(match[2]!);
			}
			currentFileOutput = [line];
			inFile = true;
		} else if (inFile) {
			currentFileOutput.push(line);
		}
	}

	if (inFile && files.length <= maxFiles) {
		output.push(...currentFileOutput);
	}

	return output.join("\n");
}

function runGit(args: string[], cwd: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
	return new Promise((resolve) => {
		const proc = spawn("git", args, { cwd, stdio: ["ignore", "pipe", "pipe"] });
		const stdoutChunks: Buffer[] = [];
		const stderrChunks: Buffer[] = [];

		proc.stdout.on("data", (chunk: Buffer) => stdoutChunks.push(chunk));
		proc.stderr.on("data", (chunk: Buffer) => stderrChunks.push(chunk));

		proc.on("close", (code) => {
			resolve({
				stdout: Buffer.concat(stdoutChunks).toString("utf-8"),
				stderr: Buffer.concat(stderrChunks).toString("utf-8"),
				exitCode: code ?? 0,
			});
		});

		proc.on("error", (err) => {
			resolve({ stdout: "", stderr: err.message, exitCode: 1 });
		});
	});
}

import type { PipelineState, TaskContext, GateResult } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";
import { runGates, GATE_CHECKS } from "../verify/gates.ts";
import { checkEvidenceCompleteness } from "../verify/evidence.ts";
import { checkStopTheLine, formatStopTheLine } from "../verify/stop-the-line.ts";
import { matchAntiRationalization } from "../verify/anti-rationalization.ts";

export interface VerifyCommandResult {
	message: string;
	state: PipelineState;
	results?: GateResult[];
}

/**
 * Handle /verify: run verification gates.
 */
export function handleVerify(
	state: PipelineState,
	ctx: TaskContext,
	config: PipelineExtensionConfig,
): VerifyCommandResult {
	if (!config.verification.enabled) {
		return { message: "Verification gates are disabled.", state };
	}

	const gateIds = [...config.verification.gates];
	if (config.verification.tddGate && !gateIds.includes("tdd")) {
		gateIds.push("tdd");
	}

	const results = runGates(ctx, gateIds);

	// Check stop-the-line
	if (config.verification.stopTheLine) {
		const stopResult = checkStopTheLine(results, config.verification.blockingGates);
		if (stopResult.blocked) {
			return {
				message: formatStopTheLine(stopResult) +
					"\n\nGate results:\n" +
					results.map((r) => `  ${r.passed ? "вң…" : "вқҢ"} ${r.gateId}: ${r.message}`).join("\n"),
				state,
				results,
			};
		}
	}

	const passed = results.every((r) => r.passed);
	const summary = results.map((r) => `  ${r.passed ? "вң…" : "вқҢ"} ${r.gateId}: ${r.message}`).join("\n");

	return {
		message: passed ? `All gates passed!\n${summary}` : `Some gates failed:\n${summary}`,
		state,
		results,
	};
}

/**
 * Handle /verify evidence: show evidence checklist.
 */
export function handleVerifyEvidence(
	state: PipelineState,
	ctx: TaskContext,
): VerifyCommandResult {
	const evidence = checkEvidenceCompleteness(ctx);

	// Check for anti-rationalization in output
	const antiRat = matchAntiRationalization(ctx.assistantOutput);

	const parts: string[] = [];
	parts.push("Evidence Checklist:");
	if (evidence.missing.length === 0) {
		parts.push("  вң… All evidence provided");
	} else {
		for (const item of evidence.missing) {
			parts.push(`  вқҢ ${item}`);
		}
	}

	if (antiRat) {
		parts.push("");
		parts.push(`вҡ пёҸ Anti-rationalization detected:`);
		parts.push(`  Excuse: "${antiRat.excuse}"`);
		parts.push(`  Reality: "${antiRat.reality}"`);
	}

	return {
		message: parts.join("\n"),
		state,
	};
}
